import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {
  const [company, setCompany] = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleAnalyze = async () => {
    setError("");
    setResults([]);

    if (!company.trim()) {
      setError("Please enter a company name or ticker symbol.");
      return;
    }

    try {
      setLoading(true);

      // ⬅️ IMPORTANT: now we send company name, not article text
      const res = await axios.post("http://localhost:5000/analyze", {
        company: company.trim(),
      });

      // expect backend to return: [{ company, impact_score }, ...]
      setResults(res.data);
    } catch (err) {
      console.error(err);
      setError(
        err.response?.data?.error ||
          "Something went wrong while analyzing. Check if backend is running."
      );
    } finally {
      setLoading(false);
    }
  };

  const formatScore = (score) => {
    if (typeof score !== "number") return score;
    return score.toFixed(2);
  };

  const getScoreClass = (score) => {
    if (score > 0.2) return "score-positive";
    if (score < -0.2) return "score-negative";
    return "score-neutral";
  };

  return (
    <div className="app-root">
      <header className="header">
        <h1>Market Sentiment Analyzer</h1>
        <p>
          Enter a company name or stock ticker and we’ll scrape recent news,
          analyze it, and show an impact score between -1.0 and 1.0.
        </p>
      </header>

      <main className="main-layout">
        <section className="input-panel">
          <h2>Company</h2>
          <input
            type="text"
            placeholder="e.g., TCS, Reliance, HDFC Bank"
            value={company}
            onChange={(e) => setCompany(e.target.value)}
          />
          <button onClick={handleAnalyze} disabled={loading}>
            {loading ? "Analyzing..." : "Analyze News Sentiment"}
          </button>
          {error && <div className="error-box">{error}</div>}
        </section>

        <section className="results-panel">
          <h2>Impact Scores</h2>
          {!results.length && !loading && !error && (
            <p className="placeholder">
              Results will appear here after you analyze a company.
            </p>
          )}

          {results.length > 0 && (
            <table className="results-table">
              <thead>
                <tr>
                  <th>Company</th>
                  <th>Impact Score</th>
                </tr>
              </thead>
              <tbody>
                {results.map((row, idx) => (
                  <tr key={idx}>
                    <td>{row.company}</td>
                    <td className={getScoreClass(row.impact_score)}>
                      {formatScore(row.impact_score)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </section>
      </main>
    </div>
  );
}

export default App;
